package test.org.apache.accumulo.test;

public class SizeCompactionStrategy extends CompactionStrategy { private long size = 0 ; @ Override public void init ( Map < String , String > options ) { size = Long . parseLong ( options . get ( "size" ) ) ; } @ Override public boolean shouldCompact ( MajorCompactionRequest request ) throws IOException { for ( DataFileValue dfv : request . getFiles ( ) . values ( ) ) if ( dfv . getSize ( ) < size ) return true ; return false ; } @ Override public CompactionPlan getCompactionPlan ( MajorCompactionRequest request ) throws IOException { CompactionPlan plan = new CompactionPlan ( ) ; for ( Entry < FileRef , DataFileValue > entry : request . getFiles ( ) . entrySet ( ) ) if ( entry . getValue ( ) . getSize ( ) < size ) plan . inputFiles . add ( entry . getKey ( ) ) ; return plan ; } }